fn cleanup_dirs(dirs_to_clean: vec<pathbuf>) {
    let mut dirs = dirs_to_clean;
    dirs.sort_by_key(|b| std::cmp::reverse(b.as_os_str().len()));
    for dir in &dirs {
        if dir.exists() {
            let _ = fs::remove_dir(dir);
        }
    }
