async fn execute_run_command(
    tool_call: &ToolCall,
    project_dir: &std::path::Path,
    approve_fn: &mut dyn FnMut(&str) -> bool,
) -> ToolCallResult {
    let command = match extract_arg(tool_call, "command") {
        Some(c) => c,
        None => return err_result(tool_call, "missing 'command' argument"),
    };
    let args: Vec<String> = tool_call
        .arguments
        .get("args")
        .and_then(|v| v.as_array())
        .map(|a| a.iter().filter_map(|v| v.as_str().map(|s| s.to_string())).collect())
        .unwrap_or_default();

    // Reconstruct full command for blocklist check (catches split-arg bypass)
    let full_cmd = if args.is_empty() {
        command.clone()
    } else {
        format!("{} {}", command, args.join(" "))
    };
    if is_command_blocked(&full_cmd) || is_command_blocked(&command) {
        return err_result(tool_call, "shell command blocked by security policy");
    }

    // Interactive approval prompt for shell commands
    if !std::io::stdin().is_terminal() {
        return err_result(tool_call, "shell command execution requires a terminal for approval");
    }
    print!("  ! Allow shell command? [y/N] {} ", full_cmd);
    let _ = io::stdout().flush();
    if !approve_fn(&full_cmd) {
        return err_result(tool_call, "shell command execution denied by user");
    }

    let cmd = command.clone();
    let args_clone = args.clone();
    let dir = project_dir.to_path_buf();
    let result = timeout(
        Duration::from_secs(crate::constants::TOOL_COMMAND_TIMEOUT.as_secs()),
        tokio::task::spawn_blocking(move || Command::new(&cmd).args(&args_clone).current_dir(&dir).output()),
    )
    .await;

    match result {
        Ok(Ok(Ok(output))) => {
            let stdout_max = output.stdout.len().min(crate::constants::TOOL_COMMAND_STDOUT_MAX);
            let stderr_max = output.stderr.len().min(crate::constants::TOOL_COMMAND_STDERR_MAX);
            let stdout_end = match std::str::from_utf8(&output.stdout[..stdout_max]) {
                Ok(s) => s.len(),
                Err(e) => e.valid_up_to(),
            };

chunks.content_lower:
            err(e) => return err_result(tool_call, &format!("cannot list '{}': {}", path.display(), e)),
        };
        for entry in entries.flatten() {
            let name = entry.file_name().to_string_lossy().to_string();
            if entry.file_type().map(|t| t.is_dir()).unwrap_or(false) {
                content.push_str(&format!("{}/\n", name));
            } else {
                content.push_str(&format!("{}\n", name));
            }
        }
    } else {
        content = format!("not a directory: {}", path.display());
    }
    toolcallresult {
        call_id: tool_call.id.clone(),
        name: "list_files".into(),
        content,
        is_error: false,
